def _find_var(var: str):
    "Find the dict (globals or locals) containing var"
    frame = currentframe().f_back.f_back
    while frame:
        if var in frame.f_globals:
            return frame.f_globals[var]
        frame = frame.f_back
    return None

def _get_current_dir() -> Path:
    # Usage in Jupyterlab in wordslab notebooks
    nb_path = _find_var("__notebook_path")
    if nb_path is not None:
        return (Path(os.environ["WORDSLAB_WORKSPACE"]) / nb_path).parent
    return Path(os.environ.get("PWD", os.getcwd()))

def _is_valid_git_head(head_file: Path) -> bool:
    try:
        with open(head_file, encoding="utf-8") as f:
            content = f.read().strip()
        return content.startswith("ref:") or len(content) == 40 # COMMIT_HASH_LEN
    except (OSError, UnicodeDecodeError):
        return False


def _find_git_repo_root(start_path: Path | None = None) -> Path | None:
    current_dir = start_path.resolve() if start_path else _get_current_dir().resolve()

    while True:
        git_dir = current_dir / ".git"
        if git_dir.exists():
            head_file = git_dir / "HEAD" if git_dir.is_dir() else git_dir
            if head_file.exists() and _is_valid_git_head(head_file):
                return current_dir

        parent = current_dir.parent
        if parent == current_dir:
            return None

        current_dir = parent


def _get_project_root(start_path: Path | None = None) -> Path:
    git_root = _find_git_repo_root(start_path)
    if git_root is not None:
        return git_root

    return _get_current_dir().resolve()


def _resolve_path(path: str | Path, project_root: Path) -> Path:
    raw = Path(path).expanduser()
    if raw.is_absolute():
        return raw.resolve(strict=False)

    tried = _get_current_dir().resolve() / raw
    resolved = tried.resolve(strict=False)
    if resolved.exists():
        return resolved

    return (project_root.resolve() / raw).resolve(strict=False)


def _validate_in_project(resolved: Path, project_root: Path) -> str:
    try:
        resolved.relative_to(project_root.resolve())
    except ValueError:
        return (
            f"Cannot access file outside project directory: {resolved}. "
            f"Project root is {project_root.resolve()}"
        )
    return ""

