# ===========================================================================
# Read file
# ===========================================================================

# Use read_file to read the content of a file. It is designed to handle large
# files safely.
#
# By default it reads from the beginning of the file. Use *offset* (0-indexed
# line number) and *limit* (max lines) to read specific parts. The return
# value includes *was_truncated* when the file was cut short.
#
# Strategy for large files:
# 1. Start with a reasonable *limit* (e.g. 1000) to get a head sample.
# 2. If truncated, decide whether you already have enough info.
# 3. Prefer targeted reads over sequential chunk-by-chunk reads.
# 4. Do not read more than 3 times on the same file without acting on what
#    you have learned.


def read_file(
    path: str | Path,
    *,
    offset: int = 0,
    limit: int = 0,
    max_bytes: int = 64_000,
) -> ReadResult:
    """Read a text file, returning content from a specific line range.

    Parameters
    ----------
    path
        Absolute or relative file path.
    offset
        0-indexed line number to start reading from. Defaults to 0.
    limit
        Maximum number of lines to read. ``None`` means no explicit
        line limit (only bounded by *max_bytes*).
    max_bytes
        Hard cap on bytes read in one call. Defaults to 64 000.

    Returns
    -------
    ReadResult
        Contains *path*, *content*, *offset*, *lines_read*, and
        *was_truncated*.

    Raises
    ------
    ValueError
        When *path* is empty, *offset* is negative, or *limit* is
        non-positive.
    FileNotFoundError
        When the path does not point to an existing file.
    IsADirectoryError
        When the path is a directory.
    """
    if isinstance(path, str) and not path.strip():
        raise ValueError("Path cannot be empty")
    if offset < 0:
        raise ValueError("Offset cannot be negative")
    if limit is not None and limit <= 0:
        raise ValueError("Limit, if provided, must be a positive number")

    file_path = Path(path).expanduser()
    if not file_path.is_absolute():
        file_path = Path.cwd() / file_path
    file_path = file_path.resolve()

    if not file_path.exists():
        raise FileNotFoundError(f"File not found at: {file_path}")
    if file_path.is_dir():
        raise IsADirectoryError(f"Path is a directory, not a file: {file_path}")

    lines: list[str] = []
    bytes_read = 0
    was_truncated = True

    with open(file_path, "rb") as f:
        line_index = 0
        while raw_line := f.readline():
            if line_index < offset:
                line_index += 1
                continue

            if limit > 0 and len(lines) >= limit:
                break

            line_bytes = len(raw_line)
            if bytes_read + line_bytes > max_bytes:
                break

            lines.append(raw_line.decode("utf-8", errors="replace"))
            bytes_read += line_bytes
            line_index += 1
        else:
            was_truncated = False

    return {
        "path": str(file_path),
        "content": "".join(lines),
        "offset": offset,
        "lines_read": len(lines),
        "was_truncated": was_truncated,
    }


# ===========================================================================
# Write file
# ===========================================================================

# Use write_file to create or overwrite a UTF-8 file.
#
# Safety:
# - Fails if the file already exists unless ``overwrite=True``.
# - Parent directories are created automatically.
#
# Best practices:
# - Always read a file before overwriting it.
# - Prefer ``search_replace`` for editing existing files.
# - Never write new files unless explicitly required.


def write_file(
    path: str | Path,
    content: str,
    *,
    overwrite: bool = False,
    max_bytes: int = 64_000,
    create_parent_dirs: bool = True,
) -> WriteResult:
    """Create or overwrite a UTF-8 text file.

    Parameters
    ----------
    path
        Absolute or relative file path.
    content
        Text to write.
    overwrite
        ``True`` to replace an existing file. Defaults to ``False``.
    max_bytes
        Hard cap for the encoded content size.
    create_parent_dirs
        Create missing parent directories automatically.

    Returns
    -------
    WriteResult
        Contains *path*, *bytes_written*, *file_existed*, and *content*.

    Raises
    ------
    ValueError
        When *path* is empty or content exceeds *max_bytes*.
    FileExistsError
        When the file exists and *overwrite* is ``False``.
    NotADirectoryError
        When a parent directory does not exist and *create_parent_dirs*
        is ``False``.
    """
    if isinstance(path, str) and not path.strip():
        raise ValueError("Path cannot be empty")

    content_bytes = len(content.encode("utf-8"))
    if content_bytes > max_bytes:
        raise ValueError(f"Content exceeds {max_bytes} bytes limit")

    file_path = Path(path).expanduser()
    if not file_path.is_absolute():
        file_path = Path.cwd() / file_path
    file_path = file_path.resolve()

    file_existed = file_path.exists()

    if file_existed and not overwrite:
        raise FileExistsError(
            f"File {file_path!r} exists. Set overwrite=True to replace."
        )

    if create_parent_dirs:
        file_path.parent.mkdir(parents=True, exist_ok=True)
    elif not file_path.parent.exists():
        raise NotADirectoryError(f"Parent directory does not exist: {file_path.parent}")

    file_path.write_text(content, encoding="utf-8")

    return {
        "path": str(file_path),
        "bytes_written": content_bytes,
        "file_existed": file_existed,
        "content": content,
    }


# ===========================================================================
# Grep
# ===========================================================================

# Use grep to recursively search for a regular expression pattern in files.
# It is fast and automatically ignores compiled artefacts and common
# build directories.

_DEFAULT_EXCLUDE: list[str] = [
    ".venv/",
    "venv/",
    "node_modules/",
    ".git/",
    "__pycache__/",
    ".pytest_cache/",
    ".mypy_cache/",
    ".tox/",
    ".nox/",
    ".coverage/",
    "htmlcov/",
    "dist/",
    "build/",
    ".idea/",
    ".vscode/",
    "*.egg-info",
    "*.pyc",
    "*.pyo",
    "*.pyd",
    ".DS_Store",
    "Thumbs.db",
    ".ipynb_checkpoints/"
]


def grep(
    pattern: str,
    path: str | Path = ".",
    *,
    max_matches: int = 100,
    max_output_bytes: int = 64_000,
    exclude_patterns: list[str] | None = None,
    case_sensitive: bool = False,
    raise_on_exc: bool = False,
) -> GrepResult:
    """Recursively search files for a regular-expression pattern.

    Parameters
    ----------
    pattern
        Regular-expression compiled by :mod:`re`.
    path
        Root directory to search. Defaults to the current working
        directory.
    max_matches
        Maximum number of match lines to return. The tool reports
        ``was_truncated=True`` when hitting this cap.
    max_output_bytes
        Hard cap on the combined length of returned match lines.
    exclude_patterns
        Glob-like patterns to skip.  Directories should end with ``/``.
        Falls back to a built-in set of common artefacts when ``None``.
    case_sensitive
        ``False`` enables case-insensitive matching.
    raise_on_exc
        ``True`` to propagate ``OSError`` from unreadable files
        instead of silently skipping them.

    Returns
    -------
    GrepResult
        Contains *matches*, *match_count*, and *was_truncated*.

    Raises
    ------
    ValueError
        When *pattern* is blank or contains invalid regex syntax.
    FileNotFoundError
        When *path* does not exist.
    """
    if not pattern.strip():
        raise ValueError("Empty search pattern provided.")

    root = Path(path).expanduser()
    if not root.is_absolute():
        root = Path.cwd() / root
    root = root.resolve()

    if not root.exists():
        raise FileNotFoundError(f"Path does not exist: {path}")

    excludes = exclude_patterns or _DEFAULT_EXCLUDE

    flags = 0 if case_sensitive else re.IGNORECASE
    try:
        compiled = re.compile(pattern, flags)
    except re.error as exc:
        raise ValueError(f"Invalid regex pattern: {exc}") from exc

    output_lines: list[str] = []
    bytes_used = 0
    truncated = False

    for fpath in _iter_files(root):
        if _should_exclude(fpath, excludes):
            continue

        if len(output_lines) >= max_matches:
            truncated = True
            break

        try:
            raw = fpath.read_bytes()
        except OSError:
            if raise_on_exc:
                raise
            continue

        if b"\x00" in raw[:8192]:
            continue

        text = raw.decode("utf-8", errors="ignore")

        for lineno, line in enumerate(text.splitlines(), start=1):
            if compiled.search(line):
                out = f"{fpath}:{lineno}:{line}"
                output_lines.append(out)
                bytes_used += len(out.encode("utf-8"))
                if bytes_used >= max_output_bytes:
                    truncated = True
                    break

        if truncated:
            break

    final_output = "\n".join(output_lines)
    final_bytes = len(final_output.encode("utf-8"))
    if final_bytes > max_output_bytes:
        truncated = True
        final_output = final_output[:max_output_bytes]

    return {
        "matches": final_output,
        "match_count": len(output_lines),
        "was_truncated": truncated,
    }


def _iter_files(root: Path) -> Iterator[Path]:
    try:
        for p in sorted(root.rglob("*"), key=lambda pth: str(pth)):
            if p.is_file():
                yield p
    except (PermissionError, OSError):
        return


def _should_exclude(fpath: Path, excludes: list[str]) -> bool:
    parts = fpath.parts
    for pat in excludes:
        if pat.endswith("/"):
            dir_name = pat.rstrip("/")
            if dir_name in parts:
                return True
        elif fnmatch.fnmatch(fpath.name, pat):
            return True
    return False


# ===========================================================================
# Search & Replace
# ===========================================================================

# Use search_replace to make targeted changes to files using SEARCH/REPLACE
# blocks. The tool finds exact text matches and replaces them.
#
# Format:
#
# <<<<<<< SEARCH
# [exact text to find in the file]
# =======
# [exact text to replace it with]
# >>>>>>> REPLACE
#
# Multiple blocks can be sent in one call; they are applied in order.
# The SEARCH text must match EXACTLY including whitespace, indentation,
# and line endings.  A fuzzy-match fallback is available for near misses.

_BLOCK_RE = re.compile(
    r"<{5,} SEARCH\r?\n(.*?)\r?\n?={5,}\r?\n(.*?)\r?\n?>{5,} REPLACE", flags=re.DOTALL
)

_BLOCK_FENCE_RE = re.compile(
    r"```[\s\S]*?\n<{5,} SEARCH\r?\n(.*?)\r?\n?={5,}\r?\n(.*?)\r?\n?>{5,} REPLACE\s*\n```",
    flags=re.DOTALL,
)


class _Block(NamedTuple):
    search: str
    replace: str


class _ApplyResult(NamedTuple):
    content: str
    applied: int
    errors: list[str]
    warnings: list[str]


class _FuzzyHit(NamedTuple):
    similarity: float
    start: int
    end: int
    text: str


def search_replace(
    file_path: str | Path,
    content: str,
    *,
    max_content_size: int = 100_000,
    fuzzy_threshold: float = 0.9,
    create_backup: bool = False,
) -> SearchResult:
    """Apply SEARCH/REPLACE blocks to an existing file.

    Parameters
    ----------
    file_path
        Path to the target file.
    content
        One or more SEARCH/REPLACE blocks following the format described
        above.
    max_content_size
        Upper bound on the patch payload in characters.
    fuzzy_threshold
        Similarity ratio (0–1) below which the fuzzy fallback gives up
        on finding a candidate region.
    create_backup
        Write ``<file>.bak`` before overwriting.

    Returns
    -------
    SearchResult
        Contains *file*, *blocks_applied*, *lines_changed*, and *warnings*.

    Raises
    ------
    ToolError
        Block search text not found, file missing, empty payload, etc.
    """
    fp = Path(file_path).expanduser()
    if not fp.is_absolute():
        fp = Path.cwd() / fp
    fp = fp.resolve()

    if not fp.exists():
        raise ToolError(f"File does not exist: {fp}")
    if not fp.is_file():
        raise ToolError(f"Path is not a file: {fp}")

    stripped = content.strip()
    if not stripped:
        raise ToolError("Empty content provided")
    if len(stripped) > max_content_size:
        raise ToolError(
            f"Content size ({len(stripped)} chars) exceeds max_content_size "
            f"({max_content_size} chars)"
        )

    blocks = _parse_blocks(stripped)
    if not blocks:
        raise ToolError(
            "No valid SEARCH/REPLACE blocks found in content.\n"
            "Expected format:\n"
            "<<<<<<< SEARCH\n[exact content to find]\n"
            "=======\n[new content]\n>>>>>>> REPLACE"
        )

    original = fp.read_text(encoding="utf-8", errors="replace")
    result = _apply_blocks(original, blocks, fp, fuzzy_threshold)

    if result.errors:
        msg = "SEARCH/REPLACE blocks failed:\n" + "\n\n".join(result.errors)
        if result.warnings:
            msg += "\n\nWarnings encountered:\n" + "\n".join(result.warnings)
        raise ToolError(msg)

    modified = result.content

    if modified == original:
        lines_changed = 0
    else:
        lines_changed = len(modified.splitlines()) - len(original.splitlines())
        if create_backup:
            shutil.copy2(fp, fp.with_suffix(fp.suffix + ".bak"))
        fp.write_text(modified, encoding="utf-8")

    return {
        "file": str(fp),
        "blocks_applied": result.applied,
        "lines_changed": lines_changed,
        "warnings": result.warnings,
    }


def _parse_blocks(content: str) -> list[_Block]:
    matches = _BLOCK_FENCE_RE.findall(content)
    if not matches:
        matches = _BLOCK_RE.findall(content)
    return [
        _Block(search=s.rstrip("\r\n"), replace=r_.rstrip("\r\n")) for s, r_ in matches
    ]


def _apply_blocks(
    content: str, blocks: list[_Block], filepath: Path, fuzzy_threshold: float
) -> _ApplyResult:
    applied = 0
    errors: list[str] = []
    warnings: list[str] = []
    current = content

    for idx, block in enumerate(blocks, 1):
        search, replace = block

        if search not in current:
            ctx = _find_search_context(current, search)
            fuzzy_ctx = _find_fuzzy_context(current, search, fuzzy_threshold)
            err = (
                f"SEARCH/REPLACE block {idx} failed: "
                f"Search text not found in {filepath}\n"
                f"Search text was:\n{search!r}\n"
                f"Context analysis:\n{ctx}"
            )
            if fuzzy_ctx:
                err += f"\n{fuzzy_ctx}"
            err += (
                "\nDebugging tips:\n"
                "1. Check for exact whitespace/indentation match\n"
                "2. Verify line endings match the file exactly\n"
                "3. Ensure the search text has not been modified by "
                "previous blocks\n"
                "4. Check for typos or case sensitivity issues"
            )
            errors.append(err)
            continue

        occurrences = current.count(search)
        if occurrences > 1:
            warnings.append(
                f"Search text in block {idx} appears {occurrences} "
                "times. Only the first occurrence will be replaced."
            )

        current = current.replace(search, replace, 1)
        applied += 1

    return _ApplyResult(current, applied, errors, warnings)


def _find_search_context(content: str, search_text: str, max_ctx: int = 5) -> str:
    lines = content.split("\n")
    slines = search_text.split("\n")

    if not slines:
        return "Search text is empty"

    first = slines[0].strip()
    if not first:
        return "First line of search text is empty or whitespace only"

    hits = [i for i, ln in enumerate(lines) if first in ln]
    if not hits:
        return f"First search line {first!r} not found anywhere in file"

    parts: list[str] = []
    for m in hits[:3]:
        lo = max(0, m - max_ctx)
        hi = min(len(lines), m + max_ctx + 1)
        parts.append(f"\nPotential match area around line {m + 1}:")
        for i in range(lo, hi):
            tag = ">>>" if i == m else "   "
            parts.append(f"{tag} {i + 1:3d}: {lines[i]}")

    return "\n".join(parts)


def _find_fuzzy_context(content: str, search_text: str, threshold: float) -> str | None:
    best = _best_fuzzy(content, search_text, threshold)
    if best is None:
        return None

    t1 = search_text.splitlines(keepends=True)
    t2 = best.text.splitlines(keepends=True)
    t1 = [l if l.endswith("\n") else l + "\n" for l in t1]
    t2 = [l if l.endswith("\n") else l + "\n" for l in t2]

    diff = list(
        difflib.unified_diff(t1, t2, fromfile="SEARCH", tofile="CLOSEST MATCH", n=3)
    )
    diff_text = "".join(diff)[:2000].rstrip()

    return (
        f"Closest fuzzy match (similarity {best.similarity * 100:.1f}%) "
        f"at lines {best.start}–{best.end}:\n"
        f"```diff\n{diff_text}\n```"
    )


def _best_fuzzy(content: str, search_text: str, threshold: float) -> _FuzzyHit | None:
    clines = content.split("\n")
    slines = search_text.split("\n")
    wsize = len(slines)

    if wsize == 0:
        return None

    anchors = [sl for sl in slines if sl.strip()]
    if not anchors:
        return None

    first_a = anchors[0]
    last_a = anchors[-1] if len(anchors) > 1 else first_a

    candidates = _find_candidates(clines, wsize, first_a, last_a)

    best: _FuzzyHit | None = None
    best_sim = 0.0
    for s in candidates:
        e = s + wsize
        window = "\n".join(clines[s:e])
        sim = difflib.SequenceMatcher(None, search_text, window).ratio()
        if sim >= threshold and sim > best_sim:
            best_sim = sim
            best = _FuzzyHit(sim, s + 1, e, window)
    return best


def _find_candidates(
    clines: list[str], wsize: int, first_a: str, last_a: str
) -> set[int]:
    candidates: set[int] = set()
    spread = 5
    for i, line in enumerate(clines):
        if first_a in line or last_a in line:
            lo = max(0, i - spread)
            hi = min(len(clines) - wsize + 1, i + spread + 1)
            candidates.update(range(lo, hi))

    if not candidates:
        max_pos = min(len(clines) - wsize + 1, 100)
        candidates = set(range(0, max_pos))
    return candidates


