"""
Tavily MCP Client Wrappers

Direct Python wrappers around the Tavily MCP server tools, using TavilyClient.
Tool and parameter descriptions are reproduced verbatim from the MCP server.

MCP Server: tavily-mcp v3.2.4
Endpoint: https://mcp.tavily.com/mcp/
"""

def _get_client():
    """Get a TavilyClient instance, raising a helpful error if the API key is missing."""
    from tavily import TavilyClient
    api_key = os.environ.get('TAVILY_API_KEY')
    if not api_key:
        raise RuntimeError('TAVILY_API_KEY environment variable is not set. Please set it before calling Tavily MCP tools.')
    return TavilyClient(api_key=api_key)

def _wrap_response(result) -> dict:
    """Wrap a successful API result in a standard response dict."""
    return {'success': True, 'result': result}

def _wrap_error(e: Exception, tool_name: str) -> dict:
    """Wrap an exception in a standard error response with LLM-friendly guidance."""
    error_msg = str(e)
    if '401' in error_msg or 'Unauthorized' in error_msg or 'invalid_token' in error_msg:
        return {'success': False, 'error': f'Tavily API authentication failed for {tool_name}. The TAVILY_API_KEY environment variable is set but the value is invalid, expired, or revoked. Please check your Tavily dashboard and verify the API key.'}
    elif '429' in error_msg or 'rate' in error_msg.lower():
        return {'success': False, 'error': f'Tavily rate limit exceeded for {tool_name}. Too many requests in a short window. Wait 30-60 seconds before retrying, or reduce request frequency. If using the free plan, consider upgrading.'}
    elif 'timed out' in error_msg.lower() or 'timeout' in error_msg.lower():
        return {'success': False, 'error': f'Request to Tavily timed out for {tool_name}. The operation took too long. Try reducing max_depth, max_breadth, limit, or increase the timeout parameter on the next attempt.'}
    elif RuntimeError('API key') is not None and 'TAVILY_API_KEY' in error_msg:
        return {'success': False, 'error': f'Missing API key for {tool_name}. Set the TAVILY_API_KEY environment variable before calling this tool.'}
    else:
        return {'success': False, 'error': f'Unexpected error calling Tavily {tool_name}: {error_msg}. Check parameters and try again. Common causes: invalid URL, malformed query, or transient network issues.'}

def tavily_search(query: str, max_results: int=5, search_depth: str='basic', topic: str='general', time_range: Optional[str]=None, include_images: bool=False, include_image_descriptions: bool=False, include_raw_content: bool=False, include_domains: Optional[List[str]]=None, exclude_domains: Optional[List[str]]=None, country: str='', include_favicon: bool=False, start_date: str='', end_date: str='', exact_match: Optional[bool]=None) -> str:
    """
    # TOOL: tavily_search

    Search the web for current information on any topic. Use for news, facts, or data beyond your knowledge cutoff. Returns snippets and source URLs.

    # PARAMETER DESCRIPTIONS (verbatim from MCP server):

    query:              Search query                          [required, string]
    max_results:        The maximum number of search results to return                     [int, default: 5]
    search_depth:       The depth of the search. 'basic' for generic results, 'advanced'
                        for more thorough search, 'fast' for optimized low latency with
                        high relevance, 'ultra-fast' for prioritizing latency above all
                        else                                                     [enum: basic|advanced|fast|ultra-fast, default: basic]
    topic:              The category of the search. This will determine which of our
                        agents will be used for the search                          [string, const: general, default: general]
    time_range:         The time range back from the current date to include in the
                        search results                                         [enum: day|week|month|year | null, default: null]
    include_images:     Include a list of query-related images in the response           [bool, default: false]
    include_image_descriptions: Include a list of query-related images and their
                        descriptions in the response                                [bool, default: false]
    include_raw_content: Include the cleaned and parsed HTML content of each search
                        result                                                     [bool, default: false]
    include_domains:    A list of domains to specifically include in the search results,
                        if the user asks to search on specific sites set this to the
                        domain of the site                              [array[string], default: []]
    exclude_domains:    List of domains to specifically exclude, if the user asks to
                        exclude a domain set this to the domain of the site  [array[string], default: []]
    country:            Boost search results from a specific country. Must be a full
                        country name (e.g., 'United States', 'Japan', 'Germany').
                        ISO country codes (e.g., 'us', 'jp') are not supported.
                        Available only if topic is general. See
                        https://docs.tavily.com/documentation/api-reference/search
                        for the full list of supported countries.              [string, default: ""]
    include_favicon:    Whether to include the favicon URL for each result               [bool, default: false]
    start_date:         Will return all results after the specified start date. Required
                        to be written in the format YYYY-MM-DD.                [string, default: ""]
    end_date:           Will return all results before the specified end date. Required
                        to be written in the format YYYY-MM-DD                [string, default: ""]
    exact_match:        Only return results containing the exact phrase(s) in quotes in
                        your query                                          [bool | null, default: null]
    """
    try:
        if not query or not query.strip():
            return json.dumps({'success': False, 'error': "The 'query' parameter is required and cannot be empty. Provide a search query string."}, ensure_ascii=False)
        client = _get_client()
        result = client.search(query=query, max_results=max_results, search_depth=search_depth, topic=topic, time_range=time_range, include_images=include_images, include_raw_content=include_raw_content, include_domains=include_domains, exclude_domains=exclude_domains, country=country if country else None, include_favicon=include_favicon, start_date=start_date if start_date else None, end_date=end_date if end_date else None, exact_match=exact_match)
        return json.dumps(_wrap_response(result), ensure_ascii=False, indent=2)
    except RuntimeError as e:
        if 'TAVILY_API_KEY' in str(e):
            return json.dumps(_wrap_error(e, 'tavily_search'), ensure_ascii=False, indent=2)
        raise
    except Exception as e:
        return json.dumps(_wrap_error(e, 'tavily_search'), ensure_ascii=False, indent=2)

def tavily_extract(urls: List[str], extract_depth: str='basic', include_images: bool=False, format: str='markdown', include_favicon: bool=False, query: str='') -> str:
    """
    # TOOL: tavily_extract

    Extract content from URLs. Returns raw page content in markdown or text format.

    # PARAMETER DESCRIPTIONS (verbatim from MCP server):

    urls:             List of URLs to extract content from                 [required, array[string]]
    extract_depth:    Use 'advanced' for LinkedIn, protected sites, or
                      tables/embedded content                              [enum: basic|advanced, default: basic]
    include_images:   Include images from pages                            [bool, default: false]
    format:           Output format                                        [enum: markdown|text, default: markdown]
    include_favicon:  Include favicon URLs                                 [bool, default: false]
    query:            Query to rerank content chunks by relevance          [string, default: ""]
    """
    try:
        if not urls:
            return json.dumps({'success': False, 'error': "The 'urls' parameter is required and cannot be empty. Provide at least one URL to extract content from."}, ensure_ascii=False)
        for url in urls:
            if not url.startswith(('http://', 'https://')):
                return json.dumps({'success': False, 'error': f"Invalid URL '{url}'. All URLs must start with http:// or https://. Please fix the URL and try again."}, ensure_ascii=False)
        client = _get_client()
        result = client.extract(urls=urls, extract_depth=extract_depth, include_images=include_images, format=format, include_favicon=include_favicon, query=query if query else None)
        return json.dumps(_wrap_response(result), ensure_ascii=False, indent=2)
    except RuntimeError as e:
        if 'TAVILY_API_KEY' in str(e):
            return json.dumps(_wrap_error(e, 'tavily_extract'), ensure_ascii=False, indent=2)
        raise
    except Exception as e:
        return json.dumps(_wrap_error(e, 'tavily_extract'), ensure_ascii=False, indent=2)

def tavily_crawl(url: str, max_depth: int=1, max_breadth: int=20, limit: int=50, instructions: str='', select_paths: Optional[List[str]]=None, select_domains: Optional[List[str]]=None, allow_external: bool=True, extract_depth: str='basic', format: str='markdown', include_favicon: bool=False) -> str:
    """
    # TOOL: tavily_crawl

    Crawl a website starting from a URL. Extracts content from pages with configurable depth and breadth.

    # PARAMETER DESCRIPTIONS (verbatim from MCP server):

    url:              The root URL to begin the crawl                          [required, string]
    max_depth:        Max depth of the crawl. Defines how far from the base URL
                      the crawler can explore.                                 [int, min: 1, default: 1]
    max_breadth:      Max number of links to follow per level of the tree
                      (i.e., per page)                                          [int, min: 1, default: 20]
    limit:            Total number of links the crawler will process before
                      stopping                                                  [int, min: 1, default: 50]
    instructions:     Natural language instructions for the crawler. Instructions
                      specify which types of pages the crawler should return.   [string, default: ""]
    select_paths:     Regex patterns to select only URLs with specific path
                      patterns (e.g., /docs/.*, /api/v1.*)                 [array[string], default: []]
    select_domains:   Regex patterns to restrict crawling to specific domains or
                      subdomains (e.g., ^docs\\.example\\.com$)         [array[string], default: []]
    allow_external:   Whether to return external links in the final response     [bool, default: true]
    extract_depth:    Advanced extraction retrieves more data, including tables
                      and embedded content, with higher success but may increase
                      latency                                                  [enum: basic|advanced, default: basic]
    format:           The format of the extracted web page content. markdown
                      returns content in markdown format. text returns plain
                      text and may increase latency.                          [enum: markdown|text, default: markdown]
    include_favicon:  Whether to include the favicon URL for each result         [bool, default: false]
    """
    try:
        if not url or not url.strip():
            return json.dumps({'success': False, 'error': "The 'url' parameter is required and cannot be empty. Provide a root URL to start crawling from."}, ensure_ascii=False)
        if not url.startswith(('http://', 'https://')):
            return json.dumps({'success': False, 'error': f"Invalid URL '{url}'. The URL must start with http:// or https://. Please fix the URL and try again."}, ensure_ascii=False)
        if max_depth < 1:
            return json.dumps({'success': False, 'error': f"'max_depth' must be >= 1 but got {max_depth}. Please provide a valid minimum depth of 1."}, ensure_ascii=False)
        if max_breadth < 1:
            return json.dumps({'success': False, 'error': f"'max_breadth' must be >= 1 but got {max_breadth}. Please provide a valid minimum breadth of 1."}, ensure_ascii=False)
        if limit < 1:
            return json.dumps({'success': False, 'error': f"'limit' must be >= 1 but got {limit}. Please provide a valid minimum limit of 1."}, ensure_ascii=False)
        client = _get_client()
        result = client.crawl(url=url, max_depth=max_depth, max_breadth=max_breadth, limit=limit, instructions=instructions if instructions else None, select_paths=select_paths, select_domains=select_domains, allow_external=allow_external, extract_depth=extract_depth, format=format, include_favicon=include_favicon)
        return json.dumps(_wrap_response(result), ensure_ascii=False, indent=2)
    except RuntimeError as e:
        if 'TAVILY_API_KEY' in str(e):
            return json.dumps(_wrap_error(e, 'tavily_crawl'), ensure_ascii=False, indent=2)
        raise
    except Exception as e:
        return json.dumps(_wrap_error(e, 'tavily_crawl'), ensure_ascii=False, indent=2)

